"use strict";parserFactory.register("erofus.com",()=>new ErofusParser);class ErofusParserImageCollector extends ImageCollector{constructor(){super()}selectImageUrlFromImagePage(e){if(null!=e.querySelector("div#picture-full img"))return e.querySelector("div#picture-full img").src}}class ErofusParser extends Parser{constructor(){super(new ErofusParserImageCollector)}async getChapterUrls(e){return[...e.querySelectorAll("div a div.thumbnail")].map(e=>util.hyperLinkToChapter(e.parentElement)).filter(e=>!util.isNullOrEmpty(e.title))}findContent(e){return e.querySelector("div.content")}findCoverImageUrl(){return null}}